begin
	g_merge : for i in 0 to ChannelCount_g-1 generate
		ParallelMerged(<WIDTH>*(i+1)-1 downto <WIDTH>*i) <= Parallel(i);
	end generate;

	i_inst : entity work.psi_common_par_tdm
