6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This is the time division multixed data mux testbench
11	-- One can select the wanted frequency clock and strobe signal then the TB
12	-- generates stimuli through the DUT as expected TDM data + strobe
13	-- data value geenrated are equal to channel number to ease the TB check 
14	------------------------------------------------------------------------------
15	-- Libraries
16	------------------------------------------------------------------------------
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.numeric_std.all;
20	use ieee.math_real.all;
21	
22	use work.psi_common_math_pkg.all;
23	use work.psi_tb_txt_util.all;
24	
25	------------------------------------------------------------
26	-- Entity Declaration
27	------------------------------------------------------------
28	entity psi_common_tdm_mux_tb is
29	  generic(rst_pol_g     : std_logic := '1';
30	          freq_clock_g  : real      := 100.0e6;
31	          freq_str_g    : real      := 0.1e6;
32	          num_channel_g : natural   := 64;
33	          data_length_g : natural   := 24;
34	          str_del_g     : natural   := 0);
35	end entity;
36	
37	------------------------------------------------------------
38	-- Architecture
39	------------------------------------------------------------
40	architecture tb of psi_common_tdm_mux_tb is
41	  constant period_c         : time                                                   := (1 sec) / freq_clock_g;
42	  signal InClk_sti          : std_logic                                              := '0';
43	  signal InRst_sti          : std_logic                                              := rst_pol_g;
44	  signal InVld_sti          : std_logic                                              := '0';
45	  signal InChSel_sti        : std_logic_vector(log2ceil(num_channel_g) - 1 downto 0) := (others => '0');
46	  signal InTdmVld_sti       : std_logic;
47	  signal InTdmDat_sti       : std_logic_vector(data_length_g - 1 downto 0);
48	  signal OutTdmVld_obs      : std_logic;
49	  signal OutTdmDat_obs      : std_logic_vector(data_length_g - 1 downto 0);
50	  --
51	  signal tb_run             : boolean                                                := true;
52	  -- TODO modify
53	  shared variable str_dff_v : std_logic_vector(num_channel_g - 1 downto 0);
54	  ------------------------------------------------------------------------------
55	  -- this procedure simply fixed parallel array to TDM output
56	  -- data values are channel numbers for easy test	
57	  ------------------------------------------------------------------------------
58	  procedure par_tdm_tb_proc(constant n_ch      : natural   := 8;
59	                            constant width     : natural   := 16;
60	                            constant rst_pol_g : std_logic := '1';
61	                            signal rst         : in std_logic;
62	                            signal clk         : in std_logic;
63	                            signal tb_run      : in boolean;
64	                            signal str         : in std_logic;
65	                            signal str_o       : out std_logic;
66	                            signal dat_o       : out std_logic_vector) is
67	    type array_data_t is array (n_ch - 1 downto 0) of std_logic_vector(width - 1 downto 0);
68	    variable array_data_v : array_data_t;
69	    variable count_v      : integer range 0 to n_ch := 0;
70	
71	  begin
72	    while tb_run loop
73	      wait until rising_edge(clk);
74	      if rst = rst_pol_g then
75	        for i in 0 to n_ch - 1 loop
76	          array_data_v(i) := std_logic_vector(to_unsigned(i, width));
77	        end loop;
78	        count_v   := 0;
79	        str_dff_v := (others => '0');
80	        str_o     <= '0';
81	      else
82	        str_dff_v(0)                       := str;
83	        str_dff_v(str_dff_v'high downto 1) := str_dff_v(str_dff_v'high - 1 downto 0);
84	        --shift reg
85	        if unsigned(str_dff_v) >= to_unsigned(0, str_dff_v'length) and count_v < n_ch then
86	          dat_o   <= array_data_v(count_v);
87	          count_v := count_v + 1;
88	          str_o   <= '1';
89	          if str_del_g > 0 then
90	            wait until rising_edge(clk);
91	            str_o <= '0';
92	            for i in 1 to str_del_g - 1 loop
93	              wait until rising_edge(clk);
94	            end loop;
95	          end if;
96	        elsif count_v = n_ch and InVld_sti = '0' then
97	          count_v := n_ch;
98	          str_o   <= '0';
99	        else
100	          count_v := 0;
101	          str_o   <= '0';
102	        end if;
103	
104	      end if;
105	    end loop;
106	  end procedure;
107	  ------------------------------------------------------------------------------
108	  -- TODO set this procedure into testbench psi_testbench pkg 
109	  -- This procdure generate strobe signal depending on:
110	  -- clock freq &wanted strobe freq - strobe is one clock cycle
111	  ------------------------------------------------------------------------------
112	  procedure tb_str_proc(constant freq_clock : real      := 100.0E6;
113	                        constant freq_str   : real      := 1.0E6;
114	                        constant rst_pol_g  : std_logic := '1';
115	                        signal rst          : in std_logic;
116	                        signal clk          : in std_logic;
117	                        signal tb_run       : in boolean;
118	                        signal str_o        : out std_logic) is
119	
120	    variable count_v : integer range 0 to (integer(ceil(freq_clock / freq_str))) := 0;
121	
122	  begin
123	    while tb_run loop
124	      wait until rising_edge(clk);
125	      if rst = rst_pol_g then
126	        count_v := 0;
127	        str_o   <= '0';
128	      else
129	        if count_v /= integer(ceil(freq_clock / freq_str)) - 1 then
130	          str_o   <= '0';
131	          count_v := count_v + 1;
132	        else
133	          str_o   <= '1';
134	          count_v := 0;
135	        end if;
136	
137	      end if;
138	    end loop;
139	  end procedure;
